        Console.WriteLine("MY_FLAG not set, using default");
    }
}

static bool IsEnvironmentVariableDefined(string name)
{
    // IDictionary enumerates every defined variable, including empty ones
    var env = Environment.GetEnvironmentVariables();
    return env.Contains(name);
}

