using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now writes entry names as
        // UTF-8 by default (sets the EFS/Language-encoding flag).
        // Our legacy Java consumer expects Shift-JIS filenames, so we
        // must pass the Shift-JIS encoding explicitly to suppress UTF-8.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("Shift_JIS");

        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: [FromKeyedServices("cache")] now throws
// InvalidOperationException if the service is registered as non-keyed.
// Register with the matching key so the DI container resolves it.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

